import React, { useMemo } from 'react';
import { useCurrentFrame, useVideoConfig, interpolate } from 'remotion';

export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const words = useMemo(() => [
    "OFFICIAL", "STAFF", "FBI", "NSA", "INTELLIGENCE", "THREAT", "UNDETECTED", "FAILURE"
  ].filter(w => w !== '' && w !== ' ' && !w.startsWith('WORD_')), []);

  const totalWords = words.length;
  const durationPerWord = 25;
  const startDelay = 30;

  return (
    <div style={{
      position: 'absolute',
      top: 0,
      left: 0,
      width: 1920,
      height: 1080,
      backgroundColor: '#1A1A1A',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      overflow: 'hidden'
    }}>
      <div style={{
        width: 1600,
        display: 'flex',
        flexWrap: 'wrap',
        gap: '40px 60px',
        justifyContent: 'center',
        alignItems: 'center'
      }}>
        {words.map((word, i) => {
          const wordStart = startDelay + (i * durationPerWord);
          const wordEnd = wordStart + 20;

          const opacity = interpolate(frame, [wordStart, wordEnd], [0.2, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const scale = interpolate(frame, [wordStart, wordStart + 10, wordEnd], [0.8, 1.1, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const glow = interpolate(frame, [wordStart, wordEnd], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

          const isActive = frame >= wordStart;

          return (
            <div key={i} style={{
              position: 'relative',
              fontSize: 96,
              fontWeight: 900,
              fontFamily: 'sans-serif',
              color: isActive ? '#AAFF00' : '#555555',
              opacity,
              transform: `scale(${scale})`,
              textShadow: (isActive && glow > 0.5) ? `0 0 30px #FF2222` : 'none',
              transition: 'all 0.2s ease-out',
              letterSpacing: '2px'
            }}>
              {word}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default AnimationComponent;

