export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const words = useMemo(() => [
    "GROUP", "NAMES", "THREAT", "INTELLIGENCE", "FIRM", "TRACKING", "THEM", "ANALYSIS"
  ].filter(w => w !== '' && w !== ' ' && !w.startsWith('WORD_')), []);

  const totalWords = words.length;
  const durationPerWord = 25;
  const startDelay = 30;

  return (
    <div style={{
      position: 'absolute',
      top: 0,
      left: 0,
      width: 1920,
      height: 1080,
      backgroundColor: '#1A1A1A',
      display: 'flex',
