          const wordStart = startDelay + (i * durationPerWord);
          const wordEnd = wordStart + 20;

          const opacity = interpolate(frame, [wordStart, wordEnd], [0.2, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
