  const rows = useMemo(() => {
    const filled = rawRows.filter(r => r !== '' && r !== ' ' && !r.startsWith('ROW_'));
    return filled.length > 0 ? filled : [
      "48 65 6c 6c 6f 20 57 6f 72 6c 64 21",
      "53 79 73 74 65 6d 20 42 72 65 61 63 68",
      "41 6e 61 6c 79 7a 69 6e 67 20 44 61 74 61",
