              const text = hexToAscii(row);
              const charCount = text.length;
              const visibleChars = Math.floor(interpolate(frame, [scrollStart + (i * 10) + 20, scrollStart + (i * 10) + 40], [0, charCount], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }));

              return (
