export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { width, height } = useVideoConfig();

  const title = 'ESCALATION DETECTED';
  const subtitle = 'US LEGISLATIVE BRANCH';
  const severity = 'CRITICAL'; // e.g. CRITICAL, WARNING, INFO
  const timestamp = 'DECEMBER 2025';
  const description = 'HOUSE COMMITTEES COMPROMISED';

  // Determine severity color
  const isCritical = severity.toUpperCase().includes('CRITICAL') || severity.toUpperCase().includes('HIGH');
  const isWarning = severity.toUpperCase().includes('WARNING') || severity.toUpperCase().includes('MED');
  const severityColor = isCritical ? '#e63946' : isWarning ? '#f4a261' : '#4fc3f7';

  // Entrance animations
  const cardScale = interpolate(frame, [0, 25], [0.95, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const cardOpacity = interpolate(frame, [0, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const cardTranslateY = interpolate(frame, [0, 25], [50, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const contentReveal = interpolate(frame, [20, 45], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const contentTranslateX = interpolate(frame, [20, 45], [-20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  // Pulse animation for the background
  const pulseScale = interpolate(frame % 60, [0, 60], [1, 1.2], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const pulseOpacity = interpolate(frame % 60, [0, 30, 60], [0, 0.4, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  return (
    <div style={{ 
      position: 'absolute', 
      top: 0, 
      left: 0, 
      width: 1920, 
      height: 1080, 
      overflow: 'hidden', 
      backgroundColor: '#1A1A1A',
      fontFamily: 'Inter, system-ui, sans-serif'
    }}>
      {/* Dynamic Background Pulse */}
      <div style={{
        position: 'absolute',
        top: '50%',
        left: '50%',
        width: '1200px',
        height: '1200px',
        transform: `translate(-50%, -50%) scale(${pulseScale})`,
        borderRadius: '50%',
        border: `2px solid ${severityColor}`,
        opacity: pulseOpacity,
        zIndex: 0
      }} />

      {/* Main Alert Card */}
      <div style={{ 
        position: 'absolute', 
        top: '50%', 
        left: '50%', 
        transform: `translate(-50%, -50%) scale(${cardScale}) translateY(${cardTranslateY}px)`,
        width: '1100px', 
        backgroundColor: 'rgba(15, 23, 42, 0.8)', // Dark slate blue base
        backdropFilter: 'blur(24px)',
        borderRadius: '32px',
        border: '2px solid rgba(255, 255, 255, 0.1)',
        boxShadow: `0 32px 64px rgba(0, 0, 0, 0.4), 0 0 20px ${severityColor}22`,
        display: 'flex',
        overflow: 'hidden',
        opacity: cardOpacity,
        zIndex: 1
      }}>
        {/* Severity Sidebar */}
        <div style={{
          width: '12px',
          backgroundColor: severityColor,
          boxShadow: `0 0 20px ${severityColor}`
        }} />

        {/* Content Area */}
        <div style={{ 
          flex: 1, 
          padding: '60px 80px', 
          opacity: contentReveal,
          transform: `translateX(${contentTranslateX}px)`
        }}>
          {/* Header Row */}
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            marginBottom: '40px' 
          }}>
            <div style={{ 
              backgroundColor: `${severityColor}22`,
              color: severityColor,
              padding: '8px 24px',
              borderRadius: '100px',
              fontSize: '20px',
              fontWeight: 800,
              letterSpacing: '0.1em',
              border: `1px solid ${severityColor}44`,
              textTransform: 'uppercase'
            }}>
              {severity}
            </div>
            <div style={{ 
              color: 'rgba(255, 255, 255, 0.5)', 
              fontSize: '20px', 
              fontFamily: 'monospace',
              letterSpacing: '0.05em' 
            }}>
              {timestamp}
            </div>
          </div>

          {/* Main Content */}
          <div style={{ marginBottom: '16px' }}>
            <div style={{ 
              color: '#AAFF00', 
              fontSize: '64px', 
              fontWeight: 900, 
              lineHeight: 1.1,
              letterSpacing: '-0.03em',
              marginBottom: '16px'
            }}>
              {title}
            </div>
            {subtitle && (
              <div style={{ 
                color: '#FF2222', 
                fontSize: '24px', 
                fontWeight: 600, 
                opacity: 0.9,
                letterSpacing: '0.02em',
                marginBottom: '32px'
              }}>
                {subtitle}
              </div>
            )}
          </div>

          <div style={{
            height: '2px',
            width: '100px',
            backgroundColor: 'rgba(255, 255, 255, 0.1)',
            marginBottom: '32px'
          }} />

          <div style={{ 
            color: 'rgba(255, 255, 255, 0.8)', 
            fontSize: '26px', 
            fontWeight: 400, 
            lineHeight: 1.6,
            maxWidth: '850px' 
          }}>
            {description}
          </div>
        </div>
      </div>

      {/* Decorative Corner Accents */}
      <div style={{
        position: 'absolute',
        top: '60px',
        right: '60px',
        color: 'rgba(255, 255, 255, 0.1)',
        fontSize: '14px',
        fontFamily: 'monospace',
        textAlign: 'right'
      }}>
        SYSTEM_OVERRIDE_ACTIVE<br />
        SECURE_CHANNEL_v4.2
      </div>
    </div>
  );
};

export default AnimationComponent;

import React, { useMemo } from 'react';
import { useCurrentFrame, useVideoConfig, interpolate } from 'remotion';

export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { width, height, durationInFrames, fps } = useVideoConfig();

  const title = 'ATTACK EVOLUTION';
  const footer = 'SALT TYPHOON 2025';
  const rawSteps = ['RECON', 'TELECOM BREACH', 'WIRETAPPING', 'LATERAL MOVEMENT', 'LEGISLATIVE ACCESS', 'DATA EXFIL', 'PERSISTENCE'];

  const steps = useMemo(() => {
    const filled = rawSteps.filter(s => s !== '' && s !== ' ' && !s.startsWith('STEP_'));
    return filled.length > 0 ? filled : ["Reconnaissance", "Weaponization", "Delivery", "Exploitation", "Installation", "C2", "Actions"];
  }, []);

  const count = steps.length;

  // Layout parameters
  const startX = 180;
  const endX = 1740;
  const totalW = endX - startX;
  const centerY = 480;
  const nodeSize = 160;

  // Timing configuration
  const startDelay = 20;
  const endDelay = 40;
  const availableFrames = durationInFrames - startDelay - endDelay;
  const framesPerStep = Math.floor(availableFrames / count);

  // Entrance Animations
  const titleOp = interpolate(frame, [0, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const titleTy = interpolate(frame, [0, 20], [20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden',
      backgroundColor: '#1A1A1A',
      fontFamily: 'Inter, system-ui, sans-serif'
    }}>
      {/* Background Decor */}
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.02) 0%, transparent 80%), linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px)',
        backgroundSize: '100% 100%, 80px 80px, 80px 80px',
        opacity: 0.5
      }} />

      {/* Header */}
      <div style={{ position: 'absolute', top: 80, left: 100, opacity: titleOp, transform: `translateY(${titleTy}px)`, zIndex: 10 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
          <div style={{ width: 12, height: 48, backgroundColor: '#AAFF00', borderRadius: 4, boxShadow: '0 0 20px #AAFF00' }} />
          <div style={{ fontSize: 48, fontWeight: 900, color: '#fff', letterSpacing: '0.1em', textTransform: 'uppercase' }}>
            {title}
          </div>
        </div>
        <div style={{ fontSize: 24, color: '#555555', marginLeft: 36, marginTop: 4, fontWeight: 600, letterSpacing: '0.05em' }}>
          CYBER_KILL_CHAIN_PROGRESSION
        </div>
      </div>

      {/* Connection Track Layer */}
      <div style={{ position: 'absolute', top: centerY - 6, left: startX, width: totalW, height: 12, backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: 6, zIndex: 1 }} />
      <div style={{ 
        position: 'absolute', top: centerY - 6, left: startX, 
        width: interpolate(frame, [startDelay, durationInFrames - endDelay], [0, totalW], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }), 
        height: 12, backgroundColor: '#AAFF00', borderRadius: 6, zIndex: 1,
        boxShadow: '0 0 20px #AAFF00'
      }} />

      {/* Steps Layer */}
      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', zIndex: 2 }}>
        {steps.map((step, i) => {
          const x = startX + (count > 1 ? (totalW / (count - 1)) * i : totalW / 2);
          const appearFrame = startDelay + (i * framesPerStep);

          const op = interpolate(frame, [appearFrame, appearFrame + 15], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const sc = interpolate(frame, [appearFrame, appearFrame + 15], [0.8, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const cardTy = interpolate(frame, [appearFrame + 5, appearFrame + 20], [30, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

          const isActive = frame >= appearFrame;

          return (
            <React.Fragment key={i}>
              {/* Step Circle Node */}
              <div style={{
                position: 'absolute', top: centerY, left: x, transform: `translate(-50%, -50%) scale(${sc})`,
                width: nodeSize, height: nodeSize, borderRadius: '50%',
                backgroundColor: 'rgba(15, 23, 42, 0.95)',
                border: `6px solid ${isActive ? '#AAFF00' : 'rgba(255,255,255,0.1)'}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                boxShadow: isActive ? `0 0 40px ${'#AAFF00'}44, inset 0 0 20px ${'#AAFF00'}22` : 'none',
                opacity: op, zIndex: 3, transition: 'border-color 0.3s'
              }}>
                <div style={{ color: isActive ? '#AAFF00' : 'rgba(255,255,255,0.2)', fontSize: 64, fontWeight: 900, fontFamily: 'monospace' }}>
                  {i + 1}
                </div>
                {/* Internal Pulsing Ring */}
                {isActive && (
                   <div style={{
                     position: 'absolute', width: '100%', height: '100%', borderRadius: '50%',
                     border: '2px solid #AAFF00',
                     opacity: interpolate(frame % 30, [0, 30], [0.6, 0]),
                     transform: `scale(${interpolate(frame % 30, [0, 30], [1, 1.3])})`
                   }} />
                )}
              </div>

              {/* Step Label Card */}
              <div style={{
                position: 'absolute', top: centerY + 120, left: x, transform: `translateX(-50%) translateY(${cardTy}px)`,
                width: 220, padding: '24px 20px',
                backgroundColor: 'rgba(15, 23, 42, 0.85)', backdropFilter: 'blur(16px)',
                borderRadius: 16, border: `1px solid ${isActive ? 'rgba(255,255,255,0.2)' : 'rgba(255,255,255,0.05)'}`,
                boxShadow: '0 20px 40px rgba(0,0,0,0.5)', opacity: op,
                textAlign: 'center', borderTop: `4px solid ${isActive ? '#AAFF00' : 'transparent'}`
              }}>
                <div style={{
                  color: isActive ? '#AAFF00' : 'rgba(255,255,255,0.4)',
                  fontSize: 14, fontWeight: 800, letterSpacing: '0.15em', textTransform: 'uppercase', marginBottom: 8
                }}>
                  PHASE 0{i + 1}
                </div>
                <div style={{
                  color: 'rgba(255,255,255,0.95)', fontSize: 22, fontWeight: 700, lineHeight: 1.2
                }}>
                  {step}
                </div>
              </div>
            </React.Fragment>
          );
        })}
      </div>

      {/* Footer Info Box */}
      <div style={{
        position: 'absolute', bottom: 60, left: '50%', transform: 'translateX(-50%)',
        width: 1000, height: 80, backgroundColor: 'rgba(0,0,0,0.6)',
        backdropFilter: 'blur(20px)', borderRadius: 12, border: '1px solid rgba(255,255,255,0.1)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        opacity: interpolate(frame, [durationInFrames - 60, durationInFrames - 40], [0, 1], { extrapolateLeft: 'clamp' })
      }}>
        <div style={{ color: '#FF2222', fontSize: 24, fontWeight: 700, letterSpacing: '0.05em' }}>
           {footer}
        </div>
      </div>
    </div>
  );
};

export default AnimationComponent;

