        </div>

        {/* Forensic detail tag */}
        <div style={{ position: 'absolute', bottom: 40, right: 60, opacity: 0.1 }}>
           <div style={{ color: '#fff', fontSize: 12, fontFamily: 'monospace', textAlign: 'right' }}>
              VERDICT_ALGORITHM: v2.1-SECURE<br />
              EXECUTION_BY: SYSTEM_AUTO
