import React from 'react'
import { useCurrentFrame, interpolate } from 'remotion'

export const AnimationComponent = () => {
  const frame = useCurrentFrame()

  const titleOp = interpolate(frame, [0, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const titleTy = interpolate(frame, [0, 20], [20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const barW = interpolate(frame, [10, 40], [0, 1920], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const axisOp = interpolate(frame, [15, 30], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })

  const b1H = interpolate(frame, [25, 50], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const b2H = interpolate(frame, [32, 57], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const b3H = interpolate(frame, [39, 64], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const b4H = interpolate(frame, [46, 71], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const b5H = interpolate(frame, [53, 78], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const labelOp = interpolate(frame, [70, 84], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })

  const title = "REGULATORY PROGRESS"
  
  // Filter out any inputs that are completely empty strings or placeholders
  const rawWaterfalls = ["INITIAL RULES", "IMPLEMENTATION", "REVOCATION", "VULNERABILITY", "EXPOSURE"]
  const rawBarValues = ["100", "50", "-100", "50", "100"]
  const rawHeights = [280, -120, 180, -80, 300]
  
  // Combine into data objects and filter out missing ones
  const activeData = rawWaterfalls.map((label, i) => ({
    label: label,
    val: rawBarValues[i],
    h: rawHeights[i]
  })).filter(d => 
    d.label && d.label !== '' && d.label !== 'Placeholder' &&
    d.val && d.val !== '' && d.val !== 'Placeholder'
  )
  
  const waterfalls = activeData.map(d => d.label)
  const barValues = activeData.map(d => d.val)
  const barHeights = activeData.map(d => d.h)
  const isPositive = barHeights.map(h => h > 0)
  
  // Dynamic widths based on how many bars actually exist
  const barCount = barHeights.length
  
  // If no bars exist, prevent math errors
  if (barCount === 0) {
    return <div style={{ backgroundColor: '#1A1A1A', width: 1920, height: 1080 }} />
  }

  const grows = [b1H, b2H, b3H, b4H, b5H].slice(0, barCount)

  const chartH = 500
  const chartBottom = 780
  
  // Calculate dynamic spacing
  const totalW = 1200 // Fixed chart width
  const barGap = barCount > 1 ? 80 : 0
  const barWidth = (totalW - (barGap * (barCount - 1))) / barCount
  const startX = (1920 - totalW) / 2

  // Waterfall offsets — each bar starts where last left off
  let runningY = chartBottom
  const barTops: number[] = []
  barHeights.forEach((h, i) => {
    if (h > 0) {
      barTops.push(runningY - Math.abs(h))
      runningY -= Math.abs(h)
    } else {
      barTops.push(runningY)
      runningY += Math.abs(h)
    }
  })

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#1A1A1A' }}>
      <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 5, overflow: 'hidden', backgroundColor: '#AAFF00', opacity: titleOp }} />
      <div style={{ position: 'absolute', top: 1074, left: 0, width: barW, height: 6, overflow: 'hidden', backgroundColor: '#AAFF00' }} />
      <div style={{ position: 'absolute', top: 60, left: 0, width: 1920, height: 60, overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: titleOp, transform: `translateY(${titleTy}px)` }}>
        <span style={{ fontSize: 28, fontWeight: 700, color: '#AAFF00', letterSpacing: 5, textTransform: 'uppercase', fontFamily: 'sans-serif' }}>{title}</span>
      </div>
      <svg width={1920} height={1080} style={{ position: 'absolute', top: 0, left: 0 }}>
        <line x1={startX - 20} y1={chartBottom} x2={startX + totalW + 20} y2={chartBottom} stroke="#00CCEE" strokeWidth={2} opacity={axisOp} />
        {[0.25, 0.5, 0.75].map((r, i) => (
          <line key={i} x1={startX - 20} y1={chartBottom - r * chartH} x2={startX + totalW + 20} y2={chartBottom - r * chartH} stroke="#333333" strokeWidth={1} strokeDasharray="6 4" opacity={axisOp} />
        ))}
        {/* Connector lines between bars */}
        {barTops.map((top, i) => {
          if (i === barTops.length - 1) return null
          const x1 = startX + i * (barWidth + barGap) + barWidth
          const x2 = startX + (i + 1) * (barWidth + barGap)
          const nextTop = barTops[i + 1]
          const connY = isPositive[i] ? top : top + Math.abs(barHeights[i])
          return <line key={i} x1={x1} y1={connY} x2={x2} y2={connY} stroke="#333333" strokeWidth={1} strokeDasharray="4 3" opacity={axisOp} />
        })}
      </svg>
      {barHeights.map((h, i) => {
        const x = startX + i * (barWidth + barGap)
        const absH = Math.abs(h) * grows[i]
        const top = isPositive[i] ? barTops[i] + Math.abs(h) * (1 - grows[i]) : barTops[i]
        return (
          <div key={i}>
            <div style={{ position: 'absolute', top, left: x, width: barWidth, height: absH, overflow: 'hidden', backgroundColor: isPositive[i] ? '#AAFF00' : '#00CCEE', borderRadius: isPositive[i] ? '4px 4px 0 0' : '0 0 4px 4px' }} />
            <div style={{ position: 'absolute', top: isPositive[i] ? barTops[i] - 48 : barTops[i] + Math.abs(h) + 8, left: x, width: barWidth, height: 40, overflow: 'hidden', opacity: labelOp, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <span style={{ fontSize: 24, fontWeight: 800, color: isPositive[i] ? '#AAFF00' : '#00CCEE', fontFamily: 'sans-serif' }}>{barValues[i]}</span>
            </div>
            <div style={{ position: 'absolute', top: chartBottom + 16, left: x, width: barWidth, height: 40, overflow: 'hidden', opacity: labelOp, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <span style={{ fontSize: 20, fontWeight: 500, color: '#555555', fontFamily: 'sans-serif', textAlign: 'center' }}>{waterfalls[i]}</span>
            </div>
          </div>
        )
      })}
    </div>
  )
}

export default AnimationComponent

import React, { useMemo } from 'react'
import { useCurrentFrame, useVideoConfig, interpolate, Easing } from 'remotion'

export const AnimationComponent = () => {
  const frame = useCurrentFrame()
  const { width, height } = useVideoConfig()

  const title = "GLOBAL VULNERABILITY"
  const arcFrom = "USA"
  const rawTargetLabels = ["NORTH AMERICA", "EUROPE", "ASIA", "GLOBAL NETWORKS"]
  const rawTargets = [
    { x: 380,  y: 350 },
    { x: 790,  y: 280 },
    { x: 820,  y: 540 },
    { x: 1380, y: 580 },
  ]

  const filteredData = useMemo(() => {
    return rawTargetLabels
      .map((label, index) => ({ label, target: rawTargets[index] }))
      .filter(item => item.label !== '' && item.label !== 'Placeholder')
  }, [rawTargetLabels])

  const mapOp = interpolate(frame, [0, 30], [0, 1], { extrapolateRight: 'clamp' })
  const arcProgress = interpolate(frame, [30, 80], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.bezier(0.4, 0, 0.2, 1) })
  const labelOp = interpolate(frame, [70, 95], [0, 1], { extrapolateRight: 'clamp' })

  const source = { x: 1100, y: 380 }

  const getArcPath = (from: {x: number, y: number}, to: {x: number, y: number}) => {
    const cpx = (from.x + to.x) / 2
    const cpy = Math.min(from.y, to.y) - Math.abs(to.x - from.x) * 0.3
    return `M ${from.x} ${from.y} Q ${cpx} ${cpy} ${to.x} ${to.y}`
  }

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#1A1A1A', fontFamily: 'Inter, system-ui, sans-serif' }}>
      
      {/* Cinematic Background Grid */}
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.02) 0%, transparent 80%), linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px)',
        backgroundSize: '100% 100%, 80px 80px, 80px 80px',
        opacity: mapOp * 0.6
      }} />

      {/* Modern Header */}
      <div style={{ 
          position: 'absolute', top: 60, left: 80, 
          opacity: mapOp, transform: `translateY(${interpolate(frame, [0, 30], [20, 0], { extrapolateRight: 'clamp' })}px)`,
          zIndex: 20 
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <div style={{ width: 6, height: 40, backgroundColor: '#AAFF00', borderRadius: 3, boxShadow: '0 0 15px #AAFF00' }} />
          <div style={{ fontSize: 42, fontWeight: 900, color: '#fff', letterSpacing: '0.1em', textTransform: 'uppercase' }}>{title}</div>
        </div>
        <div style={{ fontSize: 14, color: '#FF2222', fontWeight: 800, letterSpacing: '0.4em', textTransform: 'uppercase', marginTop: 10, marginLeft: 26 }}>GLOBAL_OPERATIONS_MAP_v2.4</div>
      </div>

      <svg width={1920} height={1080} style={{ position: 'absolute', top: 0, left: 0 }}>
        <defs>
          <linearGradient id="arcGrad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#AAFF00" stopOpacity="0" />
            <stop offset="50%" stopColor="#FF2222" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#00CCEE" stopOpacity="0" />
          </linearGradient>
          <filter id="glow">
            <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
            <feMerge>
              <feMergeNode in="coloredBlur"/>
              <feMergeNode in="SourceGraphic"/>
            </feMerge>
          </filter>
        </defs>

        {/* Connection Arcs */}
        {filteredData.map((item, i) => {
          const path = getArcPath(source, item.target)
          return (
            <g key={`arc-${i}`}>
              {/* Static Background Arc */}
              <path 
                d={path} 
                fill="none" 
                stroke="#AAFF00" 
                strokeWidth={2} 
                opacity={mapOp * 0.15} 
                strokeDasharray="4 4" 
              />
              
              {/* Animated Reveal Arc */}
              <path 
                d={path} 
                fill="none" 
                stroke="#FF2222" 
                strokeWidth={3} 
                strokeDasharray="1000"
                strokeDashoffset={1000 * (1 - arcProgress)}
                opacity={0.8}
                filter="url(#glow)"
              />

              {/* Data Flow Particle */}
              <circle r={4} fill="#fff" filter="url(#glow)">
                <animateMotion 
                  path={path} 
                  dur={`${2 + i * 0.5}s`} 
                  repeatCount="indefinite" 
                  begin={`${i * 0.3}s`}
                />
              </circle>
            </g>
          )
        })}

        {/* Source Node */}
        <g opacity={mapOp}>
          <circle cx={source.x} cy={source.y} r={24} fill="rgba(15, 23, 42, 0.9)" stroke="#AAFF00" strokeWidth={2} />
          <circle cx={source.x} cy={source.y} r={8} fill="#AAFF00" filter="url(#glow)">
            <animate attributeName="r" values="6;10;6" dur="2s" repeatCount="indefinite" />
          </circle>
        </g>

        {/* Target Dots */}
        {filteredData.map((item, i) => (
          <g key={`dot-${i}`} opacity={labelOp}>
            <circle cx={item.target.x} cy={item.target.y} r={18} fill="none" stroke="#FF2222" strokeWidth={1} opacity={0.3}>
                <animate attributeName="r" values="18;28;18" dur="3s" repeatCount="indefinite" />
            </circle>
            <circle cx={item.target.x} cy={item.target.y} r={6} fill="#FF2222" filter="url(#glow)" />
          </g>
        ))}
      </svg>

      {/* Source Label (Glass) */}
      <div style={{ 
        position: 'absolute', top: source.y - 80, left: source.x - 100, 
        width: 200, padding: '10px', backgroundColor: 'rgba(15, 23, 42, 0.9)', 
        backdropFilter: 'blur(12px)', border: '1px solid #AAFF00', 
        borderRadius: 8, opacity: mapOp, textAlign: 'center'
      }}>
        <div style={{ fontSize: 10, color: '#AAFF00', fontWeight: 900, letterSpacing: '0.2em', marginBottom: 4 }}>ORIGIN_NODE</div>
        <div style={{ fontSize: 16, fontWeight: 700, color: '#fff', textTransform: 'uppercase' }}>{arcFrom}</div>
      </div>

      {/* Target Labels */}
      {filteredData.map((item, i) => (
        <div key={`label-${i}`} style={{ 
            position: 'absolute', top: item.target.y + 30, left: item.target.x - 100, 
            width: 200, opacity: labelOp, textAlign: 'center' 
        }}>
          <div style={{ fontSize: 18, fontWeight: 800, color: '#fff', textTransform: 'uppercase', letterSpacing: '0.05em', textShadow: '0 2px 10px rgba(0,0,0,0.5)' }}>{item.label}</div>
          <div style={{ height: 2, width: 40, backgroundColor: '#FF2222', margin: '8px auto', opacity: 0.6 }} />
        </div>
      ))}

      {/* Bottom Forensic Detail */}
      <div style={{ position: 'absolute', bottom: 40, right: 60, opacity: 0.2, textAlign: 'right' }}>
         <div style={{ color: '#fff', fontSize: 12, fontFamily: 'monospace' }}>
            COORD_MAPPING: ENABLED<br />
            ACTIVE_CONNECTIONS: {filteredData.length}<br />
            STATUS: SECURE_RELAY_OK
         </div>
      </div>
    </div>
  )
}

