import React, { useMemo } from 'react'
import { useCurrentFrame, useVideoConfig, interpolate } from 'remotion'

export const AnimationComponent = () => {
  const frame = useCurrentFrame()
  const { width, height, durationInFrames } = useVideoConfig()

  const title = "SURVEILLANCE GRID"
  const originLabel = "TARGET"
  const rawNodeLabels = ["SATELLITE", "FIBER", "ENCRYPTION", "SIGNAL", "GATEWAY", "PROTOCOL"]

  const activeNodes = useMemo(() => {
    const filled = rawNodeLabels.filter(label => label !== '' && label !== 'Placeholder' && !label.startsWith('NODE_LABEL_'))
    return filled.length > 0 ? filled : ["GATEWAY_01", "FIREWALL_A", "DATA_STORE", "USER_ENDP", "VULN_SCAN", "BACKUP_02"]
  }, [rawNodeLabels])

  const count = activeNodes.length
  const angles = Array.from({ length: count }, (_, i) => (i * (360 / count) * Math.PI) / 180)

  // Center coordinates
  const cx = 960
  const cy = 540
  const radius = 380

  // Entrance animations
  const entryOp = interpolate(frame, [0, 25], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const centerScale = interpolate(frame, [10, 35], [0.8, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  
  // Rotating Ring Logic
  const rotation = interpolate(frame, [0, durationInFrames], [0, 90], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const rotationInv = interpolate(frame, [0, durationInFrames], [0, -45], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden',
      backgroundColor: '#1A1A1A',
      fontFamily: 'Inter, system-ui, sans-serif'
    }}>
      {/* Background Decor */}
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.02) 0%, transparent 80%), linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px)',
        backgroundSize: '100% 100%, 120px 120px, 120px 120px',
        opacity: 0.5
      }} />

      {/* Title Area */}
      <div style={{
        position: 'absolute', top: 80, left: '50%', transform: 'translateX(-50%)',
        textAlign: 'center', opacity: entryOp
      }}>
        <div style={{ fontSize: 40, fontWeight: 900, color: '#AAFF00', letterSpacing: '0.25em', textTransform: 'uppercase', marginBottom: 8 }}>
          {title}
        </div>
        <div style={{ width: 120, height: 4, backgroundColor: '#AAFF00', margin: '0 auto', boxShadow: '0 0 15px #AAFF00' }} />
      </div>

      <svg width={1920} height={1080} style={{ position: 'absolute', top: 0, left: 0, zIndex: 1 }}>
        {/* Connection Lines with Moving Pulse */}
        {angles.map((a, i) => {
          const nx = cx + radius * Math.cos(a)
          const ny = cy + radius * Math.sin(a)
          
          const lineStart = 30 + (i * 5)
          const lineEnd = 55 + (i * 5)
          const lineProgress = interpolate(frame, [lineStart, lineEnd], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
          
          const lx = cx + (nx - cx) * lineProgress
          const ly = cy + (ny - cy) * lineProgress

          // Pulse animation along the line
          const pulseProgress = (frame % 60) / 60
          const px = cx + (nx - cx) * pulseProgress
          const py = cy + (ny - cy) * pulseProgress

          return (
            <g key={`line-${i}`}>
              <line x1={cx} y1={cy} x2={nx} y2={ny} stroke="rgba(255,255,255,0.05)" strokeWidth={4} />
              <line x1={cx} y1={cy} x2={lx} y2={ly} stroke="#AAFF00" strokeWidth={4} style={{ filter: 'drop-shadow(0 0 8px #AAFF00)' }} />
              {lineProgress === 1 && (
                <circle cx={px} cy={py} r={6} fill="#fff" style={{ filter: 'drop-shadow(0 0 12px #fff)' }} opacity={interpolate(frame % 60, [0, 10, 50, 60], [0, 1, 1, 0])} />
              )}
            </g>
          )
        })}

        {/* Center Node Rotating Rings */}
        <g transform={`translate(${cx}, ${cy}) rotate(${rotation})`} opacity={entryOp}>
          <circle r={140} fill="none" stroke="#AAFF00" strokeWidth={2} strokeDasharray="40 20" opacity={0.3} />
        </g>
        <g transform={`translate(${cx}, ${cy}) rotate(${rotationInv})`} opacity={entryOp}>
          <circle r={110} fill="none" stroke="#FF2222" strokeWidth={8} strokeDasharray="10 100" opacity={0.5} />
        </g>
      </svg>

      {/* Center Node Card */}
      <div style={{
        position: 'absolute', top: cy, left: cx, transform: `translate(-50%, -50%) scale(${centerScale})`,
        width: 180, height: 180, backgroundColor: 'rgba(15, 23, 42, 0.95)',
        backdropFilter: 'blur(20px)', borderRadius: 24, border: '2px solid #AAFF00',
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        boxShadow: '0 0 40px rgba(0,0,0,0.5), 0 0 20px PRIMARY_COLOR44', zIndex: 2, opacity: entryOp
      }}>
        <div style={{ width: 40, height: 40, backgroundColor: '#AAFF00', borderRadius: 8, marginBottom: 16, boxShadow: '0 0 15px #AAFF00' }} />
        <div style={{ color: 'rgba(255,255,255,0.95)', fontSize: 20, fontWeight: 800, textAlign: 'center', letterSpacing: '0.05em', padding: '0 10px' }}>
          {originLabel}
        </div>
      </div>

      {/* Outer Nodes */}
      {angles.map((a, i) => {
        const nx = cx + radius * Math.cos(a)
        const ny = cy + radius * Math.sin(a)
        
        const appearStart = 50 + (i * 5)
        const op = interpolate(frame, [appearStart, appearStart + 15], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
        const sc = interpolate(frame, [appearStart, appearStart + 15], [0.8, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })

        return (
          <div key={`outer-${i}`} style={{
            position: 'absolute', top: ny, left: nx, transform: `translate(-50%, -50%) scale(${sc})`,
            opacity: op, width: 220, padding: '20px',
            backgroundColor: 'rgba(15, 23, 42, 0.85)', backdropFilter: 'blur(16px)',
            borderRadius: 16, border: '1px solid rgba(255,255,255,0.15)',
            boxShadow: '0 12px 32px rgba(0,0,0,0.4)', zIndex: 2,
            display: 'flex', alignItems: 'center', gap: 16
          }}>
            <div style={{ width: 12, height: 12, borderRadius: '50%', backgroundColor: '#FF2222', boxShadow: '0 0 10px #FF2222' }} />
            <div style={{ color: 'rgba(255,255,255,0.9)', fontSize: 18, fontWeight: 600, letterSpacing: '0.02em', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {activeNodes[i]}
            </div>
          </div>
        )
      })}
    </div>
  )
}

export default AnimationComponent

import React, { useMemo } from 'react';
import { useCurrentFrame, useVideoConfig, interpolate, Easing } from 'remotion';

export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { width, height, durationInFrames } = useVideoConfig();

  const contactName = 'CHENGDU_NODE';
  const statusText = 'RECORDING ACTIVE';

  const rawMessages = [
    { text: 'CONNECTION ESTABLISHED', sender: 'SYSTEM' },
    { text: 'AUDIO STREAM START', sender: 'SYSTEM' },
    { text: 'DATA CAPTURE', sender: 'SYSTEM' },
    { text: 'PERSISTENCE CONFIRMED', sender: 'SYSTEM' },
    { text: 'FILE SAVED', sender: 'SYSTEM' },
    { text: 'STILL RECORDING', sender: 'SYSTEM' },
  ];

  const messages = useMemo(() => {
    const filled = rawMessages.filter(m => m.text !== '' && m.text !== ' ' && !m.text.startsWith('MSG_'));
    return filled.length > 0 ? filled : [
      { text: "Have you seen the latest logs?", sender: "THEM" },
      { text: "Just checking now. Why?", sender: "ME" },
      { text: "Something isn't right with the API gateway.", sender: "THEM" },
      { text: "I see it. High latency on node 04.", sender: "ME" }
    ];
  }, []);

  const count = messages.length;
  const startDelay = 30;
  const endDelay = 40;
  const framesPerMsg = Math.floor((durationInFrames - startDelay - endDelay) / count);

  // Background Entrance
  const entryOp = interpolate(frame, [0, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden',
      backgroundColor: '#FFF0EE', fontFamily: 'Inter, system-ui, sans-serif',
      display: 'flex', justifyContent: 'center'
    }}>
      
      {/* Phone-style background container */}
      <div style={{
        width: 1000, height: '100%', backgroundColor: 'rgba(15, 23, 42, 0.95)',
        borderLeft: '1px solid rgba(255,255,255,0.1)', borderRight: '1px solid rgba(255,255,255,0.1)',
        display: 'flex', flexDirection: 'column', opacity: entryOp, boxShadow: '0 0 100px rgba(0,0,0,0.5)'
      }}>
        
        {/* Header Bar */}
        <div style={{
          height: 160, backgroundColor: 'rgba(255,255,255,0.03)', borderBottom: '1px solid rgba(255,255,255,0.1)',
          display: 'flex', alignItems: 'center', padding: '0 60px', gap: 30
        }}>
          {/* Avatar */}
          <div style={{
            width: 80, height: 80, borderRadius: '50%', backgroundColor: '#FF2222',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 32, fontWeight: 900, color: '#FFF0EE',
            boxShadow: '0 0 20px PRIMARY_COLOR44'
          }}>
            {contactName.substring(0, 1).toUpperCase()}
          </div>
          
          <div style={{ flex: 1 }}>
            <div style={{ color: '#fff', fontSize: 32, fontWeight: 800 }}>{contactName}</div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <div style={{ width: 10, height: 10, borderRadius: '50%', backgroundColor: '#2a9d5c', boxShadow: '0 0 10px #2a9d5c' }} />
              <div style={{ color: 'rgba(255,255,255,0.4)', fontSize: 18, fontWeight: 600 }}>{statusText}</div>
            </div>
          </div>

          <div style={{ color: 'rgba(255,255,255,0.2)', fontSize: 32 }}>⋮</div>
        </div>

        {/* Message Thread Area */}
        <div style={{ 
            flex: 1, 
            padding: '40px 60px', 
            display: 'flex', 
            flexDirection: 'column', 
            gap: 30,
            overflow: 'hidden', // Ensure nothing leaves this box
            position: 'relative'
        }}>
          {/* Scrollable Inner Container */}
          <div style={{
              display: 'flex',
              flexDirection: 'column',
              gap: 30,
              // Calculate a shift to keep newer messages visible if they exceed the container
              // This is a simple version; real scrolling would need more logic
              transform: messages.length > 4 ? `translateY(-${(messages.length - 4) * 120}px)` : 'none',
              transition: 'transform 0.5s ease-in-out'
          }}>
            {messages.map((msg, i) => {
                const isMe = msg.sender.toUpperCase() === 'ME';
                const appearFrame = startDelay + (i * framesPerMsg);
                
                const op = interpolate(frame, [appearFrame, appearFrame + 12], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
                const sc = interpolate(frame, [appearFrame, appearFrame + 15], [0.85, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.backOut });
                const tx = interpolate(frame, [appearFrame, appearFrame + 12], [isMe ? 40 : -40, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

                const bubbleBg = isMe ? '#FF2222' : 'rgba(255,255,255,0.08)';
                const textColor = isMe ? '#FFF0EE' : 'rgba(255,255,255,0.95)';

                return (
                <div key={i} style={{
                    alignSelf: isMe ? 'flex-end' : 'flex-start',
                    maxWidth: '85%', opacity: op, transform: `translateX(${tx}px) scale(${sc})`,
                    display: 'flex', flexDirection: 'column', alignItems: isMe ? 'flex-end' : 'flex-start'
                }}>
                    <div style={{
                    backgroundColor: bubbleBg, padding: '24px 32px',
                    borderRadius: isMe ? '32px 32px 4px 32px' : '32px 32px 32px 4px',
                    boxShadow: '0 10px 30px rgba(0,0,0,0.2)',
                    fontSize: 26, fontWeight: 500, lineHeight: 1.4, color: textColor
                    }}>
                    {msg.text}
                    </div>
                    <div style={{ marginTop: 8, fontSize: 16, color: 'rgba(255,255,255,0.2)', fontWeight: 600 }}>
                    {new Date(1693526400000 + i * 60000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </div>
                </div>
                );
            })}
          </div>
        </div>

        {/* Bottom Input Bar Placeholder */}
        <div style={{
          height: 120, borderTop: '1px solid rgba(255,255,255,0.1)', display: 'flex', alignItems: 'center', padding: '0 40px', gap: 24
        }}>
          <div style={{ width: 48, height: 48, borderRadius: '50%', border: '2px solid rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.2)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24 }}>+</div>
          <div style={{ flex: 1, height: 56, borderRadius: 28, border: '1px solid rgba(255,255,255,0.1)', backgroundColor: 'rgba(255,255,255,0.02)', padding: '0 24px', display: 'flex', alignItems: 'center', color: 'rgba(255,255,255,0.2)', fontSize: 20 }}>Type a message...</div>
          <div style={{ width: 48, height: 48, borderRadius: '50%', backgroundColor: '#FF2222', opacity: 0.3 }} />
        </div>

      </div>

      {/* Security Banner top right */}
      <div style={{ position: 'absolute', top: 40, right: 40, display: 'flex', alignItems: 'center', gap: 12, opacity: 0.2 }}>
         <div style={{ width: 14, height: 14, border: '2px solid #fff', borderRadius: 2 }} />
         <div style={{ fontSize: 14, color: '#fff', fontWeight: 800, letterSpacing: '0.1em' }}>E2EE_ACTIVE</div>
      </div>

    </div>
  );
};

export default AnimationComponent;
